import pika
import json
import time
import sys
from datetime import datetime
import threading


class RabbitMQPublisher:
    def __init__(self, host='localhost', port=5672, queue_name='task_queue'):
        self.host = host
        self.port = port
        self.queue_name = queue_name
        self.connection = None
        self.channel = None
        
    def connect(self):
        self.connection = pika.BlockingConnection(
            pika.ConnectionParameters(host=self.host, port=self.port)
        )
        self.channel = self.connection.channel()
        self.channel.queue_declare(queue=self.queue_name, durable=True)
        
    def publish_task(self, task_data):
        if not self.connection or self.connection.is_closed:
            self.connect()
            
        message = json.dumps({
            'task_id': task_data.get('task_id'),
            'task_type': task_data.get('task_type'),
            'payload': task_data.get('payload'),
            'timestamp': datetime.now().isoformat()
        })
        
        self.channel.basic_publish(
            exchange='',
            routing_key=self.queue_name,
            body=message,
            properties=pika.BasicProperties(
                delivery_mode=2,
            )
        )
        print(f"[Publisher] Sent task: {task_data.get('task_id')}")
        
    def close(self):
        if self.connection and not self.connection.is_closed:
            self.connection.close()


class RabbitMQConsumer:
    def __init__(self, host='localhost', port=5672, queue_name='task_queue'):
        self.host = host
        self.port = port
        self.queue_name = queue_name
        self.connection = None
        self.channel = None
        
    def connect(self):
        self.connection = pika.BlockingConnection(
            pika.ConnectionParameters(host=self.host, port=self.port)
        )
        self.channel = self.connection.channel()
        self.channel.queue_declare(queue=self.queue_name, durable=True)
        self.channel.basic_qos(prefetch_count=1)
        
    def process_task(self, task_data):
        task_id = task_data.get('task_id')
        task_type = task_data.get('task_type')
        payload = task_data.get('payload')
        
        print(f"[Consumer] Processing task {task_id} of type {task_type}")
        
        time.sleep(len(payload.get('data', '')) * 0.1)
        
        print(f"[Consumer] Completed task {task_id}")
        
    def callback(self, ch, method, properties, body):
        try:
            task_data = json.loads(body)
            print(f"[Consumer] Received task: {task_data.get('task_id')}")
            
            self.process_task(task_data)
            
            ch.basic_ack(delivery_tag=method.delivery_tag)
        except Exception as e:
            print(f"[Consumer] Error processing task: {e}")
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)
            
    def start_consuming(self):
        if not self.connection or self.connection.is_closed:
            self.connect()
            
        self.channel.basic_consume(
            queue=self.queue_name,
            on_message_callback=self.callback
        )
        
        print(f"[Consumer] Waiting for tasks in queue '{self.queue_name}'...")
        self.channel.start_consuming()
        
    def stop_consuming(self):
        if self.channel:
            self.channel.stop_consuming()
            
    def close(self):
        if self.connection and not self.connection.is_closed:
            self.connection.close()


def run_publisher():
    publisher = RabbitMQPublisher()
    
    try:
        publisher.connect()
        
        tasks = [
            {
                'task_id': f'task_{i}',
                'task_type': 'data_processing',
                'payload': {
                    'data': '.' * (i + 1),
                    'priority': i % 3
                }
            }
            for i in range(1, 11)
        ]
        
        for task in tasks:
            publisher.publish_task(task)
            time.sleep(0.5)
            
        print("[Publisher] All tasks published")
        
    except Exception as e:
        print(f"[Publisher] Error: {e}")
    finally:
        publisher.close()


def run_consumer():
    consumer = RabbitMQConsumer()
    
    try:
        consumer.connect()
        consumer.start_consuming()
    except KeyboardInterrupt:
        print("\n[Consumer] Stopping consumer...")
        consumer.stop_consuming()
    except Exception as e:
        print(f"[Consumer] Error: {e}")
    finally:
        consumer.close()


def main():
    if len(sys.argv) < 2:
        print("Usage: python script.py [publisher|consumer]")
        sys.exit(1)
        
    mode = sys.argv[1].lower()
    
    if mode == 'publisher':
        run_publisher()
    elif mode == 'consumer':
        run_consumer()
    elif mode == 'both':
        consumer_thread = threading.Thread(target=run_consumer, daemon=True)
        consumer_thread.start()
        
        time.sleep(2)
        
        run_publisher()
        
        try:
            consumer_thread.join()
        except KeyboardInterrupt:
            print("\n[Main] Shutting down...")
    else:
        print("Invalid mode. Use 'publisher', 'consumer', or 'both'")
        sys.exit(1)


if __name__ == '__main__':
    main()